{
  "plan_description": "Blacklist the usb-storage kernel module to prevent automatic loading of the USB storage driver, thereby ensuring USB storage devices cannot be used.",
  "steps": [
    {
      "action": "create_file",
      "path": "/etc/modprobe.d/usb-storage.conf",
      "content": "blacklist usb-storage\n",
      "mode": "0644"
    },
    {
      "action": "run_cmd",
      "command": "depmod -a"
    }
  ],
  "rollback_steps": [
    {
      "action": "delete_file",
      "path": "/etc/modprobe.d/usb-storage.conf"
    },
    {
      "action": "run_cmd",
      "command": "depmod -a"
    }
  ],
  "validation_commands": [
    "grep -i 'usb-storage' /etc/modprobe.d/usb-storage.conf",
    "lsmod | grep usb-storage"
  ],
  "cleanup": {
    "description": "No additional cleanup required beyond verification.",
    "commands": []
  }
}
